import{_ as e,o as t,c as n,d as o}from"./app.e13ca9ec.js";const i={},a=o('<h1 id="glossary" tabindex="-1"><a class="header-anchor" href="#glossary" aria-hidden="true">#</a> Glossary</h1><ul><li><strong>Ambient Infrastructure</strong>: Ensemble of components (e.g. Watchers, Judge) and services enabling a DKMS based cryptographically secured environement for decentralised authentication and peer-to-peer interactions. Acting as duplicity detection protection.</li><li><strong>DKMS</strong> -- Decentralized Key Management System</li><li><strong>Identifier</strong> -- A sequence of characters used to refer to a digital and unique form of a label. In this project we focus on cryptographically derived identifier (Self-Certifing Identifier) from the private/public key pair and anchored into its own KEL.</li><li><strong>KEL</strong> -- Key Event Log. An authentic provenance log that keeps all the changes of the Identifier in authentic and verifiable way.</li><li><strong>OOBI</strong> -- Out of Band Introduction. A discoverability mechanism used in DKMS that is <code>out-of-band</code> (ie. via QR codes). In concert with Percolation Theory is founded upon the assumption that &quot;everyone knows something and no one knows everything&quot;.</li><li><strong>Witness</strong> -- collaborates with Controller, attestates that information has been seen at a point in time by a third party (the Witness)</li><li><strong>Watcher</strong> -- collaborates with Controller and serves for its purposes mainly for the validation purposes.</li><li><strong>Receipt</strong> -- Witness issued attestation that confirms that information has been seen at a point in time</li></ul>',2),r=[a];function s(l,c){return t(),n("div",null,r)}var h=e(i,[["render",s],["__file","glossary.html.vue"]]);export{h as default};
